class Solution:
    def maxDivScore(self, nums, divisors):
        counts = {d: 0 for d in set(divisors)}
        for x in nums:
            for d in counts:
                if x % d == 0:
                    counts[d] += 1
        ranked = sorted(divisors, key=lambda d: (-counts[d], d))
        return ranked[0]

