class Solution:
    def maxDivScore(self, nums, divisors):
        best_div = divisors[0]
        best_count = -1
        for d in divisors:
            c = 0
            for x in nums:
                if x % d == 0:
                    c += 1
            if c > best_count or (c == best_count and d < best_div):
                best_count = c
                best_div = d
        return best_div

