var maxDivScore = function(nums, divisors) {
    let bestDiv = divisors[0];
    let bestCount = -1;
    for (const d of divisors) {
        let c = 0;
        for (const x of nums) {
            if (x % d === 0) c++;
        }
        if (c > bestCount || (c === bestCount && d < bestDiv)) {
            bestCount = c;
            bestDiv = d;
        }
    }
    return bestDiv;
